// Grammar Error Detection — 150 questions across 18 sections
// Types: 'standard' (pick error part), 'passage' (numbered lines), 'correct' (pick correct sentence)
export const grammarErrorsData = [
    // ── SECTION A: Subject-Verb Agreement ──
    { id: 1, type: 'standard', section: 'Subject-Verb Agreement', parts: { A: "The board of directors, along with the CEO,", B: "have unanimously approved", C: "the new restructuring proposal.", D: "No error" }, answer: 'B', explanation: "The subject is \"The board\" (singular). \"Along with the CEO\" is an interrupting phrase. Singular subject takes singular verb → \"has unanimously approved\"." },
    { id: 2, type: 'standard', section: 'Subject-Verb Agreement', parts: { A: "Neither the manager nor the employees", B: "was informed about", C: "the sudden change in policy.", D: "No error" }, answer: 'B', explanation: "In \"Neither...nor\", the verb agrees with the subject closest to it — \"employees\" (plural). So it should be \"were informed\"." },
    { id: 3, type: 'standard', section: 'Subject-Verb Agreement', parts: { A: "The committee, as well as its sub-members,", B: "are responsible for", C: "submitting the final audit report.", D: "No error" }, answer: 'B', explanation: "\"The committee\" is the real subject. \"As well as its sub-members\" is parenthetical. Singular subject → \"is responsible\"." },
    { id: 4, type: 'standard', section: 'Subject-Verb Agreement', parts: { A: "Each of the students", B: "have submitted", C: "their assignments before the deadline.", D: "No error" }, answer: 'B', explanation: "\"Each\" is always singular. → \"has submitted\"." },
    { id: 5, type: 'standard', section: 'Subject-Verb Agreement', parts: { A: "The team of analysts", B: "have prepared", C: "a comprehensive market research report.", D: "No error" }, answer: 'B', explanation: "\"The team\" is a collective noun treated as singular in formal usage. → \"has prepared\"." },
    { id: 6, type: 'standard', section: 'Subject-Verb Agreement', parts: { A: "A number of complaints", B: "has been received", C: "by the consumer grievance cell this week.", D: "No error" }, answer: 'B', explanation: "\"A number of\" is always plural. → \"have been received\". (Contrast: \"The number of complaints has increased.\")" },
    { id: 7, type: 'standard', section: 'Subject-Verb Agreement', parts: { A: "The number of students who fail", B: "to appear for the examination", C: "have increased significantly this year.", D: "No error" }, answer: 'C', explanation: "\"The number\" is singular. → \"has increased\". (Contrast: \"A number of students have failed.\")" },
    { id: 8, type: 'standard', section: 'Subject-Verb Agreement', parts: { A: "Everyone in the office,", B: "including the directors,", C: "were present at the emergency meeting.", D: "No error" }, answer: 'C', explanation: "\"Everyone\" is singular. Interrupting phrase does not change this. → \"was present\"." },
    { id: 9, type: 'standard', section: 'Subject-Verb Agreement', parts: { A: "The data collected by the researchers", B: "indicate that", C: "the hypothesis was fundamentally flawed.", D: "No error" }, answer: 'D', explanation: "\"Data\" is the plural of \"datum\" and takes a plural verb \"indicate\". No error." },
    { id: 10, type: 'standard', section: 'Subject-Verb Agreement', parts: { A: "Not only the principal", B: "but also the teachers", C: "was held accountable for the incident.", D: "No error" }, answer: 'C', explanation: "In \"Not only...but also\", verb agrees with the subject nearest to it — \"the teachers\" (plural). → \"were held accountable\"." },
    { id: 11, type: 'standard', section: 'Subject-Verb Agreement', parts: { A: "The jury, comprising twelve members,", B: "were divided in their opinion", C: "on the verdict of the case.", D: "No error" }, answer: 'B', explanation: "\"Jury\" acting as one body takes a singular verb. → \"was divided\"." },
    { id: 12, type: 'standard', section: 'Subject-Verb Agreement', parts: { A: "Neither of the two proposals", B: "submitted by the finance team", C: "were found to be feasible.", D: "No error" }, answer: 'C', explanation: "\"Neither\" is singular. → \"was found to be feasible\"." },
    { id: 13, type: 'standard', section: 'Subject-Verb Agreement', parts: { A: "The news about the merger and the acquisition", B: "have created", C: "panic among the small shareholders.", D: "No error" }, answer: 'B', explanation: "\"News\" is always singular (uncountable). → \"has created\"." },
    { id: 14, type: 'standard', section: 'Subject-Verb Agreement', parts: { A: "The police has arrested", B: "three suspects in connection", C: "with the corporate fraud case.", D: "No error" }, answer: 'A', explanation: "\"Police\" is always plural in standard usage. → \"The police have arrested\"." },
    { id: 15, type: 'standard', section: 'Subject-Verb Agreement', parts: { A: "One of the most pressing issues", B: "that affect", C: "modern businesses is data privacy.", D: "No error" }, answer: 'D', explanation: "\"That\" refers to \"issues\" (plural), so \"affect\" is correct. \"Is\" agrees with \"one\". No error." },
    // ── SECTION B: Tense Errors ──
    { id: 16, type: 'standard', section: 'Tense Errors', parts: { A: "The company has launched", B: "its new product line", C: "last Tuesday at a grand press conference.", D: "No error" }, answer: 'A', explanation: "\"Last Tuesday\" is a specific past time marker. Present Perfect cannot be used with specific past time. → \"The company launched\"." },
    { id: 17, type: 'standard', section: 'Tense Errors', parts: { A: "By the time the auditors arrived,", B: "the management has already destroyed", C: "all the incriminating financial records.", D: "No error" }, answer: 'B', explanation: "\"By the time...arrived\" signals that one past action was completed before another. → Past Perfect: \"had already destroyed\"." },
    { id: 18, type: 'standard', section: 'Tense Errors', parts: { A: "She is working at this organisation", B: "since she completed", C: "her MBA from IIM Calcutta.", D: "No error" }, answer: 'A', explanation: "\"Since\" signals an ongoing action from a past point. → Present Perfect Continuous: \"She has been working\"." },
    { id: 19, type: 'standard', section: 'Tense Errors', parts: { A: "No sooner did the chairman resign", B: "then the board appointed", C: "a new interim CEO.", D: "No error" }, answer: 'B', explanation: "\"No sooner...than\" is the fixed correlative. \"Then\" is incorrect here. → \"than the board appointed\"." },
    { id: 20, type: 'standard', section: 'Tense Errors', parts: { A: "If the management would have acted", B: "on the early warning signs,", C: "the crisis could have been avoided.", D: "No error" }, answer: 'A', explanation: "In Third Conditional (past unreal), the if-clause uses Past Perfect, not \"would have\". → \"If the management had acted\"." },
    { id: 21, type: 'standard', section: 'Tense Errors', parts: { A: "The professor suggested", B: "that every student should submits", C: "their thesis by the end of the month.", D: "No error" }, answer: 'B', explanation: "After verbs of suggestion/recommendation, the subjunctive base form is used. → \"should submit\" (no 's')." },
    { id: 22, type: 'standard', section: 'Tense Errors', parts: { A: "It is high time", B: "the government takes", C: "strict measures against tax evasion.", D: "No error" }, answer: 'B', explanation: "\"It is high time\" requires Past Subjunctive (simple past form). → \"the government took\"." },
    { id: 23, type: 'standard', section: 'Tense Errors', parts: { A: "The team will begin the project", B: "as soon as the client will approve", C: "the revised budget estimate.", D: "No error" }, answer: 'B', explanation: "No future tense is used after time conjunctions (as soon as, when, until, before, after). → \"as soon as the client approves\"." },
    { id: 24, type: 'standard', section: 'Tense Errors', parts: { A: "I wish I would have known", B: "about the scholarship opportunity", C: "before the deadline passed.", D: "No error" }, answer: 'A', explanation: "\"I wish\" + regret about past requires Past Perfect, not \"would have\". → \"I wish I had known\"." },
    { id: 25, type: 'standard', section: 'Tense Errors', parts: { A: "The factory had been manufacturing", B: "automobile parts for thirty years", C: "before it shut down last March.", D: "No error" }, answer: 'D', explanation: "Past Perfect Continuous + \"before\" + Simple Past is the correct structure for an action ongoing until a past point. No error." },
    { id: 26, type: 'standard', section: 'Tense Errors', parts: { A: "She has been waiting for the results", B: "since the last three weeks", C: "and is extremely anxious.", D: "No error" }, answer: 'B', explanation: "\"Since\" is used with a point in time, not a duration. → \"for the last three weeks\"." },
    { id: 27, type: 'standard', section: 'Tense Errors', parts: { A: "The moment the CEO entered the room,", B: "all the employees have stood up", C: "to greet him respectfully.", D: "No error" }, answer: 'B', explanation: "\"The moment\" signals simultaneous simple past actions. → \"stood up\" (Simple Past, not Present Perfect)." },
    { id: 28, type: 'standard', section: 'Tense Errors', parts: { A: "He worked for this company", B: "for twenty years before", C: "he was offered the position of director.", D: "No error" }, answer: 'A', explanation: "An action completed before another past event requires Past Perfect. → \"He had worked for this company\"." },
    // ── SECTION C: Articles ──
    { id: 29, type: 'standard', section: 'Articles', parts: { A: "She is an honest", B: "and hardworking employee", C: "who deserves a promotion.", D: "No error" }, answer: 'D', explanation: "\"An honest\" — correct because \"honest\" starts with a vowel sound. No error." },
    { id: 30, type: 'standard', section: 'Articles', parts: { A: "The professor gave a useful advice", B: "to all the students", C: "who were preparing for competitive exams.", D: "No error" }, answer: 'A', explanation: "\"Advice\" is an uncountable noun. Articles like \"a/an\" cannot be used with uncountable nouns. → \"The professor gave useful advice\"." },
    { id: 31, type: 'standard', section: 'Articles', parts: { A: "He was appointed as the", B: "Chairman of the Board", C: "at a very young age of forty-two.", D: "No error" }, answer: 'D', explanation: "No error. This is a \"No error\" trap question." },
    { id: 32, type: 'standard', section: 'Articles', parts: { A: "The Amazon is the longest river", B: "in South America and is", C: "a lifeline for millions of people.", D: "No error" }, answer: 'D', explanation: "No error. Rivers take \"the\" — \"The Amazon\" is correct. Superlatives take \"the\". All parts are correct." },
    { id: 33, type: 'standard', section: 'Articles', parts: { A: "An MLA from the northern constituency", B: "delivered an hour-long speech", C: "on a economic policy reform.", D: "No error" }, answer: 'C', explanation: "\"Economic\" starts with a vowel sound. → \"an economic policy reform\"." },
    { id: 34, type: 'standard', section: 'Articles', parts: { A: "The accused was given a", B: "opportunity to present", C: "his defence before the tribunal.", D: "No error" }, answer: 'A', explanation: "\"Opportunity\" starts with a vowel sound. → \"an opportunity\"." },
    { id: 35, type: 'standard', section: 'Articles', parts: { A: "He plays the piano", B: "with the great skill", C: "that he developed through years of practice.", D: "No error" }, answer: 'B', explanation: "\"Great skill\" is used in a general sense here — no article is needed. → \"with great skill\"." },
    // ── SECTION D: Conjunctions ──
    { id: 36, type: 'standard', section: 'Conjunctions', parts: { A: "Though the startup had limited funding,", B: "but it managed to scale operations", C: "rapidly within just two years.", D: "No error" }, answer: 'B', explanation: "\"Though\" and \"but\" cannot be used together. Remove \"but\": \"it managed to scale operations\"." },
    { id: 37, type: 'standard', section: 'Conjunctions', parts: { A: "Either the CEO", B: "or the board members", C: "is responsible for the financial discrepancy.", D: "No error" }, answer: 'C', explanation: "In \"Either...or\", the verb agrees with the subject nearest to it — \"board members\" (plural). → \"are responsible\"." },
    { id: 38, type: 'standard', section: 'Conjunctions', parts: { A: "Although she had all the qualifications,", B: "yet she was not selected", C: "for the position of General Manager.", D: "No error" }, answer: 'B', explanation: "\"Although\" and \"yet\" cannot be used together — they are both concessive conjunctions. → Remove \"yet\"." },
    { id: 39, type: 'standard', section: 'Conjunctions', parts: { A: "He not only won the award", B: "but also given a cash prize", C: "of one lakh rupees by the organisation.", D: "No error" }, answer: 'B', explanation: "\"Not only...but also\" must maintain parallel structure. \"Won\" (active) vs \"given\" (passive) is not parallel. → \"but was also given a cash prize\"." },
    { id: 40, type: 'standard', section: 'Conjunctions', parts: { A: "The manager was both", B: "intelligent as well as experienced,", C: "which made him the ideal candidate.", D: "No error" }, answer: 'B', explanation: "\"Both...and\" is the correct correlative. \"Both...as well as\" is incorrect. → \"both intelligent and experienced\"." },
    // ── SECTION E: Prepositions ──
    { id: 41, type: 'standard', section: 'Prepositions', parts: { A: "The new marketing strategy", B: "is far superior than", C: "the one implemented last quarter.", D: "No error" }, answer: 'B', explanation: "\"Superior\" always takes \"to\", never \"than\". → \"is far superior to\"." },
    { id: 42, type: 'standard', section: 'Prepositions', parts: { A: "The accused was charged", B: "of embezzlement", C: "by the financial regulatory body.", D: "No error" }, answer: 'B', explanation: "\"Charged with\" — not \"charged of\". → \"charged with embezzlement\"." },
    { id: 43, type: 'standard', section: 'Prepositions', parts: { A: "The founder was reluctant", B: "to part with his equity", C: "despite the attractive buyout offer.", D: "No error" }, answer: 'D', explanation: "\"Part with\" + object (equity = thing) is correct. No error." },
    { id: 44, type: 'standard', section: 'Prepositions', parts: { A: "All employees must comply", B: "to the updated code of conduct", C: "issued by the HR department.", D: "No error" }, answer: 'B', explanation: "\"Comply with\" — not \"comply to\". → \"comply with the updated code of conduct\"." },
    { id: 45, type: 'standard', section: 'Prepositions', parts: { A: "The new intern is", B: "junior than all", C: "the other members of the research team.", D: "No error" }, answer: 'B', explanation: "\"Junior\" always takes \"to\", never \"than\". → \"junior to all\"." },
    { id: 46, type: 'standard', section: 'Prepositions', parts: { A: "The committee was accused", B: "for deliberately misrepresenting", C: "the financial data to the investors.", D: "No error" }, answer: 'B', explanation: "\"Accused of\" — not \"accused for\". → \"accused of deliberately misrepresenting\"." },
    { id: 47, type: 'standard', section: 'Prepositions', parts: { A: "The organisation finally", B: "agreed on the terms", C: "proposed by the government regulator.", D: "No error" }, answer: 'D', explanation: "\"Agreed on\" terms/plans after discussion is correct. No error." },
    { id: 48, type: 'standard', section: 'Prepositions', parts: { A: "The new policy is", B: "in contravention with", C: "the international trade agreements.", D: "No error" }, answer: 'B', explanation: "\"In contravention of\" — not \"in contravention with\". → \"in contravention of\"." },
    // ── SECTION F: Active / Passive Voice Errors ──
    { id: 49, type: 'standard', section: 'Active/Passive Voice', parts: { A: "The annual report was written", B: "by the finance team", C: "and submitted to board last week.", D: "No error" }, answer: 'D', explanation: "Passive voice is correctly formed. Past tense is consistent with \"last week\". No error." },
    { id: 50, type: 'standard', section: 'Active/Passive Voice', parts: { A: "The new policy is being", B: "implemented by the government", C: "since the beginning of this financial year.", D: "No error" }, answer: 'A', explanation: "\"Since\" with ongoing action requires Present Perfect Continuous — not Present Continuous. Tense mismatch with \"since\"." },
    { id: 51, type: 'standard', section: 'Active/Passive Voice', parts: { A: "The award was been given", B: "to the most deserving candidate", C: "at the annual convocation ceremony.", D: "No error" }, answer: 'A', explanation: "\"Was been given\" is grammatically incorrect. Passive voice: \"was given\" (Simple Past) or \"has been given\" (Present Perfect). → \"The award was given\"." },
    { id: 52, type: 'standard', section: 'Active/Passive Voice', parts: { A: "The project has been completed", B: "by our team", C: "three months before the deadline.", D: "No error" }, answer: 'A', explanation: "\"Three months before the deadline\" is a specific completed past event — Present Perfect is not appropriate. → \"The project was completed\"." },
    // ── SECTION G: Direct and Indirect Speech ──
    { id: 53, type: 'standard', section: 'Direct/Indirect Speech', parts: { A: "She told to me", B: "that she had already submitted", C: "the assignment to the professor.", D: "No error" }, answer: 'A', explanation: "\"Tell\" does not take \"to\" before the object. → \"She told me\"." },
    { id: 54, type: 'standard', section: 'Direct/Indirect Speech', parts: { A: "He said that he will attend", B: "the conference the", C: "following day without fail.", D: "No error" }, answer: 'A', explanation: "Indirect speech with past reporting verb requires tense backshift. \"Will\" → \"would\". → \"he would attend\"." },
    { id: 55, type: 'standard', section: 'Direct/Indirect Speech', parts: { A: "The teacher asked the students", B: "that why they had not", C: "completed the assignment on time.", D: "No error" }, answer: 'B', explanation: "In indirect questions, \"that\" and \"why/what/how\" should not both appear. → \"why they had not\"." },
    { id: 56, type: 'standard', section: 'Direct/Indirect Speech', parts: { A: "She exclaimed with joy", B: "that what a beautiful painting", C: "it was.", D: "No error" }, answer: 'B', explanation: "In indirect speech for exclamatory sentences, \"what a\" is removed. → \"that it was a very beautiful painting\"." },
    { id: 57, type: 'standard', section: 'Direct/Indirect Speech', parts: { A: "He asked me", B: "will I be attending", C: "the seminar the next morning.", D: "No error" }, answer: 'B', explanation: "In indirect questions, word order must be statement order (subject + verb), not question order. → \"whether I would be attending\"." },
    // ── SECTION H: Degrees of Comparison ──
    { id: 58, type: 'standard', section: 'Degrees of Comparison', parts: { A: "He was selected as", B: "the most best candidate", C: "for the position of Chief Financial Officer.", D: "No error" }, answer: 'B', explanation: "\"Most best\" is a double superlative — incorrect. → \"the best candidate\"." },
    { id: 59, type: 'standard', section: 'Degrees of Comparison', parts: { A: "Of the two proposals,", B: "the second one is", C: "the most innovative.", D: "No error" }, answer: 'C', explanation: "When comparing two things, comparative degree (\"more\") is used, not superlative (\"most\"). → \"the more innovative\"." },
    { id: 60, type: 'standard', section: 'Degrees of Comparison', parts: { A: "Iron is more useful", B: "than any metal", C: "found on earth.", D: "No error" }, answer: 'B', explanation: "Iron is itself a metal. \"Any metal\" would include iron. → \"than any other metal\"." },
    { id: 61, type: 'standard', section: 'Degrees of Comparison', parts: { A: "She is more smarter", B: "than all her colleagues", C: "in the department.", D: "No error" }, answer: 'A', explanation: "\"More smarter\" is a double comparative. → \"She is smarter\"." },
    { id: 62, type: 'standard', section: 'Degrees of Comparison', parts: { A: "The new model is", B: "one of the most innovative product", C: "ever launched by the company.", D: "No error" }, answer: 'B', explanation: "\"One of the most...\" is always followed by a plural noun. → \"one of the most innovative products\"." },
    // ── SECTION I: Pronouns ──
    { id: 63, type: 'standard', section: 'Pronouns', parts: { A: "Each of the managers submitted", B: "their individual report", C: "to the board by Friday.", D: "No error" }, answer: 'B', explanation: "\"Each\" is singular. \"Their\" (plural) does not agree. → \"his or her individual report\"." },
    { id: 64, type: 'standard', section: 'Pronouns', parts: { A: "Neither Rahul nor his colleagues", B: "have submitted their", C: "expense claims for last month.", D: "No error" }, answer: 'D', explanation: "\"Nor his colleagues\" (plural) is the subject nearest to the verb → \"have\" is correct. \"Their\" refers to colleagues (plural). No error." },
    { id: 65, type: 'standard', section: 'Pronouns', parts: { A: "It was her who", B: "first raised the issue of", C: "financial irregularities in the company.", D: "No error" }, answer: 'A', explanation: "After \"to be\", the subject pronoun is used, not the object pronoun. → \"It was she who\"." },
    { id: 66, type: 'standard', section: 'Pronouns', parts: { A: "Between you and I,", B: "the entire project", C: "was poorly planned from the start.", D: "No error" }, answer: 'A', explanation: "\"Between\" is a preposition and takes object pronouns. → \"Between you and me\"." },
    { id: 67, type: 'standard', section: 'Pronouns', parts: { A: "Everyone has the right", B: "to express their views", C: "freely and without fear.", D: "No error" }, answer: 'D', explanation: "In modern standard usage, \"their\" as a singular gender-neutral pronoun with \"everyone\" is accepted. No error." },
    // ── SECTION J: Modifiers and Split Infinitives ──
    { id: 68, type: 'standard', section: 'Modifiers/Infinitives', parts: { A: "The coach ordered the players", B: "to not leave", C: "the training camp under any circumstances.", D: "No error" }, answer: 'B', explanation: "The infinitive should not be split. → \"not to leave the training camp\"." },
    { id: 69, type: 'standard', section: 'Modifiers/Infinitives', parts: { A: "Walking along the road,", B: "the trees appeared", C: "to be swaying in the strong wind.", D: "No error" }, answer: 'A', explanation: "Dangling modifier — \"Walking along the road\" should modify a person, not \"the trees\". Trees cannot walk." },
    { id: 70, type: 'standard', section: 'Modifiers/Infinitives', parts: { A: "Having completed the report,", B: "it was submitted", C: "to the senior manager immediately.", D: "No error" }, answer: 'B', explanation: "Dangling participle — \"Having completed the report\" should modify a person. \"It\" (the report) cannot complete itself." },
    { id: 71, type: 'standard', section: 'Modifiers/Infinitives', parts: { A: "She decided to", B: "quickly and efficiently", C: "complete the pending work before the deadline.", D: "No error" }, answer: 'B', explanation: "Split infinitive — adverbs should not interrupt \"to + verb\". → \"to complete the pending work quickly and efficiently\"." },
    // ── SECTION K: Spelling and Word Choice ──
    { id: 72, type: 'standard', section: 'Word Choice/Spelling', parts: { A: "The principle reason", B: "for the company's success", C: "was its focus on customer satisfaction.", D: "No error" }, answer: 'A', explanation: "\"Principle\" (noun = rule) is confused with \"Principal\" (adjective = main). → \"The principal reason\"." },
    { id: 73, type: 'standard', section: 'Word Choice/Spelling', parts: { A: "The manager complemented", B: "the team on their", C: "exceptional performance this quarter.", D: "No error" }, answer: 'A', explanation: "\"Complemented\" means supplemented. The intended word is \"complimented\" (praised). → \"The manager complimented\"." },
    { id: 74, type: 'standard', section: 'Word Choice/Spelling', parts: { A: "The affect of the new policy", B: "on small businesses", C: "will be studied by the committee.", D: "No error" }, answer: 'A', explanation: "\"Affect\" is a verb. \"Effect\" is the noun. → \"The effect of the new policy\"." },
    { id: 75, type: 'standard', section: 'Word Choice/Spelling', parts: { A: "He made a stationary", B: "purchase for the office", C: "worth nearly five thousand rupees.", D: "No error" }, answer: 'A', explanation: "\"Stationary\" means not moving. \"Stationery\" means office supplies. → \"a stationery purchase\"." },
    // ── SECTION L: Miscellaneous High-Frequency Traps ──
    { id: 76, type: 'standard', section: 'Miscellaneous', parts: { A: "The committee comprises of", B: "seven senior members", C: "from various departments.", D: "No error" }, answer: 'A', explanation: "\"Comprise\" does not take \"of\". → \"The committee comprises seven senior members\"." },
    { id: 77, type: 'standard', section: 'Miscellaneous', parts: { A: "He is addicted", B: "to play video games", C: "for several hours every night.", D: "No error" }, answer: 'B', explanation: "\"Addicted to\" is followed by a noun or gerund. → \"addicted to playing video games\"." },
    { id: 78, type: 'standard', section: 'Miscellaneous', parts: { A: "Despite of the heavy rainfall,", B: "the event was conducted", C: "as per the scheduled programme.", D: "No error" }, answer: 'A', explanation: "\"Despite\" does not take \"of\". → \"Despite the heavy rainfall\"." },
    { id: 79, type: 'standard', section: 'Miscellaneous', parts: { A: "He availed the opportunity", B: "to present his findings", C: "at the international research conference.", D: "No error" }, answer: 'A', explanation: "\"Avail\" must be used reflexively — \"availed himself of\". → \"He availed himself of the opportunity\"." },
    { id: 80, type: 'standard', section: 'Miscellaneous', parts: { A: "The judge ordered that", B: "the accused be given", C: "a fair and impartial trial.", D: "No error" }, answer: 'D', explanation: "\"Ordered that...be given\" is the correct subjunctive form. No error." },
    { id: 81, type: 'standard', section: 'Miscellaneous', parts: { A: "The proposal was discussed", B: "in the meeting but a decision", C: "could not be arrived.", D: "No error" }, answer: 'C', explanation: "\"Arrive at a decision\" — the preposition \"at\" is missing. → \"could not be arrived at\"." },
    { id: 82, type: 'standard', section: 'Miscellaneous', parts: { A: "Due to he was late,", B: "the meeting had to be", C: "rescheduled for the following day.", D: "No error" }, answer: 'A', explanation: "\"Due to\" is a preposition and must be followed by a noun/noun phrase, not a clause. → \"Because he was late\"." },
    { id: 83, type: 'standard', section: 'Miscellaneous', parts: { A: "She is one of those managers", B: "who always give", C: "their full attention to employee welfare.", D: "No error" }, answer: 'D', explanation: "\"One of those managers who\" — \"who\" refers to \"managers\" (plural), so \"give\" is correct. No error." },
    { id: 84, type: 'standard', section: 'Miscellaneous', parts: { A: "The new law is applicable", B: "to all citizens", C: "irregardless of their social status.", D: "No error" }, answer: 'C', explanation: "\"Irregardless\" is not a standard word. The correct word is \"regardless\". → \"regardless of their social status\"." },
    { id: 85, type: 'standard', section: 'Miscellaneous', parts: { A: "He could not help", B: "but to laugh", C: "at the absurdity of the situation.", D: "No error" }, answer: 'B', explanation: "\"Could not help but\" is followed by the bare infinitive. → \"could not help but laugh\"." },
    // ── SECTION M: Mixed / Challenging ──
    { id: 86, type: 'standard', section: 'Mixed/Challenging', parts: { A: "The reason why he resigned", B: "is because the work environment", C: "had become increasingly hostile.", D: "No error" }, answer: 'B', explanation: "\"The reason...is because\" is redundant. → \"The reason why he resigned is that the work environment had become hostile.\"" },
    { id: 87, type: 'standard', section: 'Mixed/Challenging', parts: { A: "It was a historical moment", B: "when the first Indian woman", C: "was elected to this prestigious position.", D: "No error" }, answer: 'A', explanation: "\"A historic moment\" (memorable) vs \"a historical moment\" (related to history). → \"It was a historic moment\"." },
    { id: 88, type: 'standard', section: 'Mixed/Challenging', parts: { A: "She is more senior", B: "than me in this organisation", C: "by nearly five years.", D: "No error" }, answer: 'A', explanation: "\"Senior\" does not use \"more\". Like \"superior/inferior\", it takes \"to\". → \"She is senior to me\"." },
    { id: 89, type: 'standard', section: 'Mixed/Challenging', parts: { A: "The government's decision to", B: "heavily subsidise fuel prices", C: "has been widely appreciated.", D: "No error" }, answer: 'D', explanation: "Though there is a split infinitive, modern usage widely accepts this. No error." },
    { id: 90, type: 'standard', section: 'Mixed/Challenging', parts: { A: "Scarcely had he entered the hall", B: "when the lights", C: "went out suddenly.", D: "No error" }, answer: 'D', explanation: "\"Scarcely...when\" is a correct fixed idiom. No error." },
    { id: 91, type: 'standard', section: 'Mixed/Challenging', parts: { A: "The verdict was greeted", B: "with much hue and cry", C: "among the general public.", D: "No error" }, answer: 'C', explanation: "\"Hue and cry\" is idiomatically used with \"by\" when referring to people. → \"by the general public\"." },
    { id: 92, type: 'standard', section: 'Mixed/Challenging', parts: { A: "I prefer tea", B: "over coffee", C: "in the mornings.", D: "No error" }, answer: 'B', explanation: "\"Prefer...to\" is the standard form. → \"I prefer tea to coffee\"." },
    { id: 93, type: 'standard', section: 'Mixed/Challenging', parts: { A: "He has a flare", B: "for designing innovative", C: "digital marketing campaigns.", D: "No error" }, answer: 'A', explanation: "\"Flare\" means a burst of flame. The correct word is \"flair\" (natural talent). → \"He has a flair\"." },
    { id: 94, type: 'standard', section: 'Mixed/Challenging', parts: { A: "The committee of experts", B: "were asked to evaluate", C: "the long-term impact of the new policy.", D: "No error" }, answer: 'B', explanation: "\"The committee\" is a collective noun, singular. → \"was asked to evaluate\"." },
    { id: 95, type: 'standard', section: 'Mixed/Challenging', parts: { A: "She laid down on the couch", B: "after the long and exhausting", C: "board meeting finally ended.", D: "No error" }, answer: 'A', explanation: "\"Laid\" is past tense of \"lay\" (transitive). \"Lie\" (intransitive — to recline) → past tense is \"lay\". → \"She lay down on the couch\"." },
    { id: 96, type: 'standard', section: 'Mixed/Challenging', parts: { A: "His continuous efforts", B: "to improve the system", C: "finally bore fruit last year.", D: "No error" }, answer: 'A', explanation: "\"Continuous\" means without interruption. \"Continual\" means recurring/repeated. Efforts that recur are \"continual\". → \"His continual efforts\"." },
    { id: 97, type: 'standard', section: 'Mixed/Challenging', parts: { A: "The report clearly shows", B: "that the company has made", C: "significant progresses this year.", D: "No error" }, answer: 'C', explanation: "\"Progress\" is an uncountable noun — it has no plural form. → \"significant progress\"." },
    { id: 98, type: 'standard', section: 'Mixed/Challenging', parts: { A: "The chairman, with all his advisors,", B: "were present", C: "at the extraordinary general meeting.", D: "No error" }, answer: 'B', explanation: "\"The chairman\" is the subject. \"With all his advisors\" is an interrupting phrase. → \"was present\"." },
    { id: 99, type: 'standard', section: 'Mixed/Challenging', parts: { A: "He has been appointed", B: "as the new head of", C: "a government undertaking recently.", D: "No error" }, answer: 'D', explanation: "Present Perfect is acceptable here as there is no specific past time mentioned. No error." },
    { id: 100, type: 'standard', section: 'Mixed/Challenging', parts: { A: "Time and tide", B: "wait for", C: "no man.", D: "No error" }, answer: 'D', explanation: "\"Time and tide\" is treated as a single concept that takes plural verb \"wait\" in the standard proverb. No error." },
    // ── SECTION N: Passage-based Error Detection ──
    { id: 101, type: 'passage', section: 'Passage-based', passage: ["Education is a instrument /", "which imparts knowledge and /", "therefore indirectly controls power /", "and shapes social narratives."], answer: 'A', explanation: "\"Education is a instrument\" — \"instrument\" begins with a vowel sound. → \"an instrument\"." },
    { id: 102, type: 'passage', section: 'Passage-based', passage: ["After knowing the truth /", "they took the right decision /", "in the matter /", "and punished the real culprits."], answer: 'A', explanation: "\"After knowing\" should be \"After coming to know\" or restructured. The gerund construction is awkward here." },
    { id: 103, type: 'passage', section: 'Passage-based', passage: ["The patient died /", "despite he had received /", "the best medical help /", "from the hospital staff."], answer: 'B', explanation: "\"Despite\" is a preposition and cannot be followed by a clause. → \"despite having received\" or \"even though he had received\"." },
    { id: 104, type: 'passage', section: 'Passage-based', passage: ["He is one of those leaders /", "who always inspires /", "his team to perform /", "beyond expectations."], answer: 'B', explanation: "\"One of those leaders who\" — \"who\" refers to \"leaders\" (plural). → \"who always inspire\"." },
    { id: 105, type: 'passage', section: 'Passage-based', passage: ["The board has been considering /", "the proposal since /", "the last three months /", "without reaching a decision."], answer: 'B', explanation: "\"Since\" is used with a point in time. \"The last three months\" is a duration. → \"for the last three months\"." },
    { id: 106, type: 'passage', section: 'Passage-based', passage: ["Neither the chairman /", "nor the directors /", "was willing to /", "accept responsibility for the crisis."], answer: 'C', explanation: "\"Nor the directors\" (plural) is the subject nearest to the verb → \"were willing to\"." },
    { id: 107, type: 'passage', section: 'Passage-based', passage: ["Hardly had the ceremony ended /", "then the guests /", "began leaving the venue /", "in large numbers."], answer: 'B', explanation: "\"Hardly...when\" is the correct fixed pair. \"Then\" is incorrect. → \"when the guests\"." },
    { id: 108, type: 'passage', section: 'Passage-based', passage: ["The judge suggested /", "that the accused should be /", "given an opportunity /", "to presents his side of the story."], answer: 'D', explanation: "\"To presents\" — infinitive requires base form. → \"to present\"." },
    { id: 109, type: 'passage', section: 'Passage-based', passage: ["The new regulation applies /", "to all companies /", "irregardless of /", "their size or turnover."], answer: 'C', explanation: "\"Irregardless\" is not standard. → \"regardless of\"." },
    { id: 110, type: 'passage', section: 'Passage-based', passage: ["Due to the rising inflation, /", "the government has been forced /", "to revise its fiscal /", "policies since the past six months."], answer: 'D', explanation: "\"Since\" used with duration (the past six months) is incorrect. → \"for the past six months\"." },
    // ── SECTION O: No Error Traps ──
    { id: 111, type: 'standard', section: 'No Error Traps', parts: { A: "The committee has decided", B: "to review all pending applications", C: "before the end of this month.", D: "No error" }, answer: 'D', explanation: "No error. All parts are grammatically correct." },
    { id: 112, type: 'standard', section: 'No Error Traps', parts: { A: "He requested the manager", B: "not to transfer him", C: "to the new branch.", D: "No error" }, answer: 'D', explanation: "No error. \"Requested...not to\" is the correct reported speech + infinitive structure." },
    { id: 113, type: 'standard', section: 'No Error Traps', parts: { A: "Neither of the reports", B: "submitted by the two teams", C: "was found to be accurate.", D: "No error" }, answer: 'D', explanation: "No error. \"Neither\" is singular → \"was\" is correct." },
    { id: 114, type: 'standard', section: 'No Error Traps', parts: { A: "She has been working", B: "on this project for", C: "the past two years.", D: "No error" }, answer: 'D', explanation: "No error. Present Perfect Continuous + \"for\" + duration is correct." },
    { id: 115, type: 'standard', section: 'No Error Traps', parts: { A: "The board urged", B: "that the matter be referred", C: "to an independent arbitration committee.", D: "No error" }, answer: 'D', explanation: "No error. \"Urged that...be referred\" — correct subjunctive form." },
    // ── SECTION P: Correct Sentence Selection ──
    { id: 116, type: 'correct', section: 'Correct Sentence', prompt: "Which of the following sentences is correct?", parts: { A: "He is more senior than me by five years.", B: "She is more inferior to her predecessor.", C: "The new product is superior to the old one.", D: "He is more preferable than the other candidate." }, answer: 'C', explanation: "C is correct — \"superior to\". A uses \"more senior\" (wrong). B uses \"more inferior\" (double comparison). D uses \"more preferable\" (double comparison)." },
    { id: 117, type: 'correct', section: 'Correct Sentence', prompt: "Which of the following sentences is correct?", parts: { A: "Though he worked hard but he failed.", B: "Although he worked hard, yet he failed.", C: "Despite working hard, he failed.", D: "Even though he worked hard but he failed." }, answer: 'C', explanation: "C is correct — \"Despite + gerund\". A, B, and D all pair two concessive conjunctions together incorrectly." },
    { id: 118, type: 'correct', section: 'Correct Sentence', prompt: "Which of the following sentences is correct?", parts: { A: "The coach ordered the player to not leave the camp.", B: "The coach ordered the player not to leave the camp.", C: "The coach ordered the player for not leaving the camp.", D: "The coach ordered the player that he should not leave the camp." }, answer: 'B', explanation: "B is correct — negative infinitive: \"not to leave\". The infinitive must not be split." },
    { id: 119, type: 'correct', section: 'Correct Sentence', prompt: "Which of the following sentences is correct?", parts: { A: "He didn't liked to attend the meeting.", B: "He hadn't like to attend the meeting.", C: "He doesn't likes to attend the meeting.", D: "He didn't like to attend the meeting." }, answer: 'D', explanation: "\"Didn't\" already marks past tense — the main verb must be in base form. → \"didn't like\"." },
    { id: 120, type: 'correct', section: 'Correct Sentence', prompt: "Which of the following sentences is correct?", parts: { A: "The data shows that the results are consistent.", B: "The data show that the results are consistent.", C: "The data is showing that the results are consistent.", D: "The data have been shows that the results are consistent." }, answer: 'B', explanation: "\"Data\" is plural (singular: datum). → \"The data show\"." },
    // ── SECTION Q: Advanced / Tricky Mixed ──
    { id: 121, type: 'standard', section: 'Advanced', parts: { A: "He would rather", B: "his team submit", C: "the report today than tomorrow.", D: "No error" }, answer: 'B', explanation: "\"Would rather + subject + past subjunctive\" — \"submit\" should be \"submitted\"." },
    { id: 122, type: 'standard', section: 'Advanced', parts: { A: "Suppose the market crashes tomorrow,", B: "what will be", C: "your contingency plan?", D: "No error" }, answer: 'D', explanation: "No error. \"Suppose\" used as a conjunction with present tense for hypothetical future is acceptable." },
    { id: 123, type: 'standard', section: 'Advanced', parts: { A: "The new manager has a flare", B: "for resolving conflicts", C: "and improving team cohesion.", D: "No error" }, answer: 'A', explanation: "\"Flair\" (natural talent) is confused with \"flare\" (light/flame). → \"has a flair for\"." },
    { id: 124, type: 'standard', section: 'Advanced', parts: { A: "She is used to work", B: "long hours during", C: "the quarterly review season.", D: "No error" }, answer: 'A', explanation: "\"Used to\" as a present state requires a gerund. → \"She is used to working long hours\"." },
    { id: 125, type: 'standard', section: 'Advanced', parts: { A: "It is essential", B: "that the CEO presents", C: "the revised numbers to the board.", D: "No error" }, answer: 'B', explanation: "After \"It is essential that\", the subjunctive base form (without 's') is required. → \"that the CEO present\"." },
    { id: 126, type: 'standard', section: 'Advanced', parts: { A: "The report was comprised of", B: "seven chapters covering", C: "all aspects of the financial quarter.", D: "No error" }, answer: 'A', explanation: "\"Comprise\" does not take \"of\" in active voice. → \"The report comprised seven chapters\" or \"consisted of\"." },
    { id: 127, type: 'standard', section: 'Advanced', parts: { A: "Scarcely did he arrive", B: "than the argument", C: "broke out between the two parties.", D: "No error" }, answer: 'B', explanation: "\"Scarcely...when\" is the correct pair. \"Than\" is used with \"No sooner\". → \"when the argument broke out\"." },
    { id: 128, type: 'standard', section: 'Advanced', parts: { A: "The jury has not yet", B: "reached a uniform verdict", C: "on all the charges levelled against the accused.", D: "No error" }, answer: 'D', explanation: "No error. Correct usage throughout." },
    { id: 129, type: 'standard', section: 'Advanced', parts: { A: "He suggested me", B: "to take a short break", C: "before resuming the negotiations.", D: "No error" }, answer: 'A', explanation: "\"Suggest\" cannot take an indirect object directly. → \"He suggested that I take a short break\"." },
    { id: 130, type: 'standard', section: 'Advanced', parts: { A: "We discussed about", B: "the budget allocation", C: "during the quarterly review meeting.", D: "No error" }, answer: 'A', explanation: "\"Discuss\" is transitive and does not require \"about\". → \"We discussed the budget allocation\"." },
    { id: 131, type: 'standard', section: 'Advanced', parts: { A: "The new scheme will benefit", B: "to the farmers", C: "in the drought-prone regions.", D: "No error" }, answer: 'B', explanation: "\"Benefit\" is a transitive verb — it does not take \"to\". → \"will benefit the farmers\"." },
    { id: 132, type: 'standard', section: 'Advanced', parts: { A: "The minister emphasised", B: "on the need for", C: "greater investment in public infrastructure.", D: "No error" }, answer: 'B', explanation: "\"Emphasise\" is a transitive verb that does not take \"on\". → \"emphasised the need for\"." },
    { id: 133, type: 'standard', section: 'Advanced', parts: { A: "He was awarded", B: "for his outstanding contribution", C: "to the field of renewable energy.", D: "No error" }, answer: 'D', explanation: "No error. \"Awarded for\" is correct." },
    { id: 134, type: 'standard', section: 'Advanced', parts: { A: "The Prime Minister, along with", B: "several cabinet ministers,", C: "were present at the function.", D: "No error" }, answer: 'C', explanation: "\"The Prime Minister\" is the real subject (singular). → \"was present at the function\"." },
    { id: 135, type: 'standard', section: 'Advanced', parts: { A: "Being a rainy day,", B: "the outdoor programme", C: "had to be cancelled.", D: "No error" }, answer: 'A', explanation: "Dangling modifier — \"Being a rainy day\" cannot modify \"the outdoor programme\". → \"It being a rainy day\"." },
    // ── SECTION R: Final Challenging Round ──
    { id: 136, type: 'standard', section: 'Final Challenge', parts: { A: "The accused not only denied", B: "the charges but also refused", C: "to cooperate with the investigating authorities.", D: "No error" }, answer: 'D', explanation: "No error. Parallel structure maintained. Correct." },
    { id: 137, type: 'standard', section: 'Final Challenge', parts: { A: "The students were told", B: "that they can submit", C: "their projects the following week.", D: "No error" }, answer: 'B', explanation: "Backshift in indirect speech — \"can\" → \"could\". → \"that they could submit\"." },
    { id: 138, type: 'standard', section: 'Final Challenge', parts: { A: "He is known for being", B: "thorougher in his work", C: "than any of his contemporaries.", D: "No error" }, answer: 'B', explanation: "\"Thorougher\" is not standard. \"Thorough\" forms its comparative with \"more\". → \"more thorough in his work\"." },
    { id: 139, type: 'standard', section: 'Final Challenge', parts: { A: "The committee failed", B: "to arrive to a consensus", C: "on the proposed amendment.", D: "No error" }, answer: 'B', explanation: "The fixed idiom is \"arrive at a consensus/decision\". → \"to arrive at a consensus\"." },
    { id: 140, type: 'standard', section: 'Final Challenge', parts: { A: "She returned back", B: "to the office after", C: "attending the client meeting.", D: "No error" }, answer: 'A', explanation: "\"Returned back\" is redundant — \"return\" already implies going back. → \"She returned to the office\"." },
    { id: 141, type: 'standard', section: 'Final Challenge', parts: { A: "Let you and I", B: "resolve this issue", C: "before the next board meeting.", D: "No error" }, answer: 'A', explanation: "\"Let\" takes the object pronoun. → \"Let you and me resolve this issue\"." },
    { id: 142, type: 'standard', section: 'Final Challenge', parts: { A: "He has been", B: "working here since", C: "five years.", D: "No error" }, answer: 'C', explanation: "\"Since\" is used with a point in time. \"Five years\" is a duration. → \"for five years\"." },
    { id: 143, type: 'standard', section: 'Final Challenge', parts: { A: "The politician made", B: "an indirect allusion", C: "to the recent corruption scandal.", D: "No error" }, answer: 'B', explanation: "\"Allusion\" already means an indirect reference. \"Indirect allusion\" is redundant. → \"made an allusion to\"." },
    { id: 144, type: 'standard', section: 'Final Challenge', parts: { A: "The meeting was postponed", B: "because of the CEO", C: "was not available.", D: "No error" }, answer: 'B', explanation: "\"Because of\" is a preposition — must be followed by a noun/noun phrase, not a clause. → \"because the CEO was not available\"." },
    { id: 145, type: 'standard', section: 'Final Challenge', parts: { A: "Would you please", B: "revert back", C: "to my email at the earliest?", D: "No error" }, answer: 'B', explanation: "\"Revert\" already means to go back. \"Back\" is redundant. → \"revert to my email\"." },
    { id: 146, type: 'standard', section: 'Final Challenge', parts: { A: "The results were", B: "worst than expected,", C: "causing widespread concern.", D: "No error" }, answer: 'B', explanation: "When comparing two things, comparative form is used. → \"worse than expected\" (\"worst\" is superlative)." },
    { id: 147, type: 'standard', section: 'Final Challenge', parts: { A: "He passed away", B: "due to cancer", C: "at a relatively young age.", D: "No error" }, answer: 'D', explanation: "No error. \"Passed away due to cancer\" is grammatically acceptable." },
    { id: 148, type: 'standard', section: 'Final Challenge', parts: { A: "The decision was", B: "taken by mutual", C: "consensus of all the members.", D: "No error" }, answer: 'B', explanation: "\"Consensus\" already means general agreement. \"Mutual consensus\" is redundant. → \"by consensus of all the members\"." },
    { id: 149, type: 'standard', section: 'Final Challenge', parts: { A: "Despite of his best efforts,", B: "he could not convince", C: "the investors to fund the project.", D: "No error" }, answer: 'A', explanation: "\"Despite\" does not take \"of\". → \"Despite his best efforts\"." },
    { id: 150, type: 'standard', section: 'Final Challenge', parts: { A: "It was she", B: "who first alerted", C: "the authorities regarding the fraud.", D: "No error" }, answer: 'D', explanation: "No error. \"It was she who\" — subject pronoun correctly used after \"to be\"." },

    // ── SECTION S: Figures of Speech ──
    { id: 151, type: 'mcq', section: 'Figures of Speech', question: 'What figure of speech is used in: "The pen is mightier than the sword"?', parts: { A: 'Simile', B: 'Metaphor', C: 'Personification', D: 'Alliteration' }, answer: 'B', explanation: 'A metaphor directly equates two unlike things without using "like" or "as". "The pen" and "the sword" are being directly compared — no linking word, hence metaphor, not simile.' },
    { id: 152, type: 'mcq', section: 'Figures of Speech', question: 'What figure(s) of speech are used in: "My beloved is like a red, red rose"?', parts: { A: 'Metaphor and Personification', B: 'Simile and Alliteration', C: 'Hyperbole and Simile', D: 'Metaphor and Alliteration' }, answer: 'B', explanation: 'Exact JIPMAT 2022 Q82 — "like" marks a Simile (explicit comparison); "red, red" is Alliteration (repetition of the same initial consonant/vowel sound). Both figures coexist in the same line.' },
    { id: 153, type: 'mcq', section: 'Figures of Speech', question: 'Identify the figure of speech in: "The stars danced playfully in the moonlit sky."', parts: { A: 'Simile', B: 'Hyperbole', C: 'Personification', D: 'Oxymoron' }, answer: 'C', explanation: 'Personification — non-human entities (stars) are given a human quality (dancing playfully). No comparison word like "as" or "like" is used, so it is not a simile.' },
    { id: 154, type: 'mcq', section: 'Figures of Speech', question: '"I have told you a million times not to be late." This sentence uses:', parts: { A: 'Metaphor', B: 'Personification', C: 'Understatement', D: 'Hyperbole' }, answer: 'D', explanation: 'Hyperbole is deliberate exaggeration for emphasis. "A million times" is not literally true — it exaggerates the frequency to stress frustration. Understatement would be the opposite (downplaying).' },
    { id: 155, type: 'mcq', section: 'Figures of Speech', question: '"The silence was deafening." This is an example of:', parts: { A: 'Simile', B: 'Alliteration', C: 'Oxymoron', D: 'Personification' }, answer: 'C', explanation: 'Oxymoron combines two contradictory terms in a single phrase. "Silence" (absence of sound) and "deafening" (overwhelmingly loud) are opposites placed together to create a striking effect.' },
    { id: 156, type: 'mcq', section: 'Figures of Speech', question: '"Peter Piper picked a peck of pickled peppers." This illustrates:', parts: { A: 'Assonance', B: 'Alliteration', C: 'Onomatopoeia', D: 'Rhyme' }, answer: 'B', explanation: 'Alliteration is the repetition of the same initial consonant sound in closely connected words. Here, "P" repeats across multiple words (Peter, Piper, picked, peck, pickled, peppers). Assonance repeats vowel sounds; this is consonant repetition.' },
    { id: 157, type: 'mcq', section: 'Figures of Speech', question: '"She is as brave as a lion." This is an example of:', parts: { A: 'Metaphor', B: 'Hyperbole', C: 'Simile', D: 'Personification' }, answer: 'C', explanation: 'Simile uses "as...as" or "like" to compare two unlike things explicitly. Here, a person\'s bravery is compared to a lion\'s using "as...as". A metaphor would say "She is a lion" — without the linking word.' },
    { id: 158, type: 'mcq', section: 'Figures of Speech', question: '"The moon smiled down on the sleeping village." This uses:', parts: { A: 'Hyperbole', B: 'Oxymoron', C: 'Alliteration', D: 'Personification' }, answer: 'D', explanation: 'Personification attributes human qualities to non-human things. The moon (inanimate) is given the human action of smiling. This creates a vivid, warm image of the moonlit scene.' },

    // ── SECTION T: Idioms and Phrases ──
    { id: 159, type: 'mcq', section: 'Idioms & Phrases', question: '"He was at his wit\'s end when the project failed." The underlined idiom means:', parts: { A: 'very angry', B: 'completely exhausted', C: 'utterly confused and helpless', D: 'deeply disappointed' }, answer: 'C', explanation: '"At one\'s wit\'s end" means to have absolutely no idea what to do next — to be completely at a loss. It does not mean anger or physical exhaustion; it specifically refers to mental helplessness.' },
    { id: 160, type: 'mcq', section: 'Idioms & Phrases', question: '"The new manager decided to take the bull by the horns." This means:', parts: { A: 'to avoid a difficult situation', B: 'to tackle a problem directly and boldly', C: 'to make a situation worse', D: 'to consult others before acting' }, answer: 'B', explanation: '"Take the bull by the horns" means to deal with a difficult or dangerous situation in a direct and courageous way. It implies action and decisiveness — the opposite of avoidance.' },
    { id: 161, type: 'mcq', section: 'Idioms & Phrases', question: '"She let the cat out of the bag during the press conference." This means:', parts: { A: 'She caused chaos at the event.', B: 'She revealed a secret unintentionally.', C: 'She made an important announcement.', D: 'She brought an unexpected guest.' }, answer: 'B', explanation: '"Let the cat out of the bag" means to accidentally reveal information that was meant to be kept secret. The origin is from market tricks where a cat was hidden in a bag instead of a pig — once opened, the secret was out.' },
    { id: 162, type: 'mcq', section: 'Idioms & Phrases', question: '"The board decided to burn the midnight oil before the quarterly presentation." This means:', parts: { A: 'to destroy important documents', B: 'to celebrate a late-night success', C: 'to work very late into the night', D: 'to make hasty decisions' }, answer: 'C', explanation: '"Burn the midnight oil" means to work or study very late into the night. The phrase originates from the era of oil lamps — working past midnight meant literally burning oil. It has nothing to do with destruction or celebration.' },
    { id: 163, type: 'mcq', section: 'Idioms & Phrases', question: '"Despite all the criticism, she stood her ground." The underlined phrase means:', parts: { A: 'remained standing in one place', B: 'refused to change her position or opinion', C: 'stepped back from her responsibilities', D: 'accepted the criticism gracefully' }, answer: 'B', explanation: '"Stand one\'s ground" is an idiom meaning to maintain one\'s position firmly despite opposition or pressure. It implies resolution, not literal physical standing.' },
    { id: 164, type: 'mcq', section: 'Idioms & Phrases', question: '"The new CEO hit the ground running from day one." This means:', parts: { A: 'He faced many obstacles at the start.', B: 'He made many mistakes initially.', C: 'He started with great energy and without delay.', D: 'He resigned very quickly.' }, answer: 'C', explanation: '"Hit the ground running" means to begin a new activity with great enthusiasm and energy, making immediate and effective progress. It implies preparedness and initiative from the very beginning.' },
    { id: 165, type: 'mcq', section: 'Idioms & Phrases', question: '"The auditor\'s report opened a can of worms for the management." This means:', parts: { A: 'It resolved all issues neatly.', B: 'It revealed a complicated and problematic situation.', C: 'It introduced new business opportunities.', D: 'It created a positive impression on the board.' }, answer: 'B', explanation: '"Open a can of worms" means to create or reveal a complicated, sensitive, or problematic situation. Opening a can of worms makes a messy, hard-to-control problem — an apt metaphor for audit disclosures.' },
    { id: 166, type: 'mcq', section: 'Idioms & Phrases', question: '"He gave the new employee the cold shoulder at the meeting." This means:', parts: { A: 'He spoke harshly to the employee.', B: 'He deliberately ignored the employee.', C: 'He offered constructive feedback.', D: 'He promoted the employee unexpectedly.' }, answer: 'B', explanation: '"Give someone the cold shoulder" means to deliberately snub or ignore someone in a rude manner. It implies intentional social rejection, not verbal criticism or physical coldness.' },

    // ── SECTION U: One-Word Substitution ──
    { id: 167, type: 'mcq', section: 'One-Word Substitution', question: '"One who is indifferent to pain or pleasure."', parts: { A: 'Eccentric', B: 'Stoic', C: 'Fatalist', D: 'Philosopher' }, answer: 'B', explanation: 'Exact JIPMAT 2025 Q79 — A Stoic is a person who endures pain or hardship without complaint and is not easily swayed by pleasure either. The word derives from the ancient Greek Stoic philosophers.' },
    { id: 168, type: 'mcq', section: 'One-Word Substitution', question: '"Misappropriation of money."', parts: { A: 'Robbery', B: 'Theft', C: 'Embezzlement', D: 'Fraud' }, answer: 'C', explanation: 'Exact JIPMAT 2025 Q76 — Embezzlement specifically means the fraudulent appropriation of funds placed in one\'s trust or belonging to one\'s employer. It is distinct from theft (taking something without permission) or robbery (taking by force).' },
    { id: 169, type: 'mcq', section: 'One-Word Substitution', question: '"A person belonging to the same period as another."', parts: { A: 'Predecessor', B: 'Successor', C: 'Contemporary', D: 'Adversary' }, answer: 'C', explanation: 'Exact JIPMAT 2022 Q67 — Contemporary = a person living or occurring at the same time as another. "Predecessor" = one who came before; "successor" = one who comes after.' },
    { id: 170, type: 'mcq', section: 'One-Word Substitution', question: '"A government ruled by a king or queen."', parts: { A: 'Democracy', B: 'Oligarchy', C: 'Theocracy', D: 'Monarchy' }, answer: 'D', explanation: 'Monarchy = a form of government where a single hereditary figure (king/queen) holds supreme authority. Democracy = governed by the people; Oligarchy = ruled by a small elite; Theocracy = ruled by religious authority.' },
    { id: 171, type: 'mcq', section: 'One-Word Substitution', question: '"One who walks in sleep."', parts: { A: 'Insomniac', B: 'Hypochondriac', C: 'Somnambulist', D: 'Narcissist' }, answer: 'C', explanation: 'Somnambulist = a sleepwalker. From Latin: "somnus" (sleep) + "ambulare" (to walk). An insomniac cannot sleep; a hypochondriac worries excessively about illness; a narcissist is obsessed with themselves.' },
    { id: 172, type: 'mcq', section: 'One-Word Substitution', question: '"A doctor who treats children."', parts: { A: 'Dermatologist', B: 'Nephrologist', C: 'Cardiologist', D: 'Paediatrician' }, answer: 'D', explanation: 'Paediatrician = a doctor specialising in the medical care of children. Dermatologist treats skin conditions; Nephrologist treats kidney diseases; Cardiologist treats heart conditions.' },
    { id: 173, type: 'mcq', section: 'One-Word Substitution', question: '"The study of insects."', parts: { A: 'Ornithology', B: 'Entomology', C: 'Ecology', D: 'Ichthyology' }, answer: 'B', explanation: 'Entomology = the scientific study of insects. Ornithology = study of birds; Ecology = study of organisms and their environment; Ichthyology = study of fish. "Entomo" comes from Greek "entomon" meaning insect.' },
    { id: 174, type: 'mcq', section: 'One-Word Substitution', question: '"A speech made without prior preparation."', parts: { A: 'Soliloquy', B: 'Monologue', C: 'Extempore', D: 'Dialogue' }, answer: 'C', explanation: 'Extempore = spoken or performed without preparation; impromptu. A soliloquy is a speech made by a character to themselves; a monologue is a long speech by one person; a dialogue is conversation between two or more.' },
    { id: 175, type: 'mcq', section: 'One-Word Substitution', question: '"Extreme fear of confined spaces."', parts: { A: 'Acrophobia', B: 'Xenophobia', C: 'Claustrophobia', D: 'Agoraphobia' }, answer: 'C', explanation: 'Claustrophobia = abnormal fear of being in small or enclosed spaces. Acrophobia = fear of heights; Xenophobia = fear/dislike of foreigners; Agoraphobia = fear of open or crowded spaces.' },
    { id: 176, type: 'mcq', section: 'One-Word Substitution', question: '"A person who pretends to have virtues or beliefs they do not actually possess."', parts: { A: 'Sycophant', B: 'Hypocrite', C: 'Demagogue', D: 'Misanthrope' }, answer: 'B', explanation: 'Hypocrite = one who feigns moral qualities, virtues, or feelings they do not genuinely have. Sycophant = a flatterer; Demagogue = a political leader who uses popular prejudice; Misanthrope = one who dislikes people in general.' },

    // ── SECTION V: Synonyms ──
    { id: 177, type: 'mcq', section: 'Synonyms', question: 'Find the synonym of "EBULLIENT":', parts: { A: 'Athletic', B: 'Energetic', C: 'Lethargic', D: 'Indifferent' }, answer: 'B', explanation: 'Exact JIPMAT 2022 Q86 — Ebullient means enthusiastic and lively. "Energetic" is the closest synonym. Lethargic (sluggish) and Indifferent (uncaring) are antonyms. Athletic refers to physical fitness, not temperament.' },
    { id: 178, type: 'mcq', section: 'Synonyms', question: 'Find the synonym of "PALPABLE":', parts: { A: 'Visible', B: 'Audible', C: 'Perceivable', D: 'Presentable' }, answer: 'C', explanation: 'Exact JIPMAT 2023 Q86 — Palpable means able to be touched or felt; clearly perceptible. "Perceivable" captures both the tactile and the figurative sense (obvious). It is not limited to sight (visible) or sound (audible).' },
    { id: 179, type: 'mcq', section: 'Synonyms', question: 'Find the synonym of "REPROACH":', parts: { A: 'Appreciate', B: 'Reprimand', C: 'Approach', D: 'Ignore' }, answer: 'B', explanation: 'Exact JIPMAT 2023 Q78 — Reproach = to express disapproval or disappointment; to rebuke. Reprimand = to rebuke formally. Note the spelling trap: "Approach" is a distractor that sounds similar but means to come near.' },
    { id: 180, type: 'mcq', section: 'Synonyms', question: 'Find the synonym of "OSTENSIBLE":', parts: { A: 'Desirable', B: 'Fateful', C: 'Apparent', D: 'Genuine' }, answer: 'C', explanation: 'Exact JIPMAT 2023 Q92 — Ostensible = appearing to be true but not necessarily so. "Apparent" = seeming real but not necessarily actually real. "Genuine" is the antonym. "Desirable" and "Fateful" are unrelated.' },
    { id: 181, type: 'mcq', section: 'Synonyms', question: 'Find the synonym of "FAMISHED":', parts: { A: 'Agricultural', B: 'Prestigious', C: 'Feasible', D: 'Hungry' }, answer: 'D', explanation: 'Exact JIPMAT 2023 Q91 — Famished = extremely hungry, starved. "Hungry" is the direct synonym. The other options are completely unrelated in meaning and serve as vocabulary distractors.' },
    { id: 182, type: 'mcq', section: 'Synonyms', question: 'Find the synonym of "CALLOUS":', parts: { A: 'Passive', B: 'Careless', C: 'Insensitive', D: 'Cursed' }, answer: 'C', explanation: 'Exact JIPMAT 2025 Q74 — Callous = showing cruel disregard for others\' feelings; emotionally hardened. "Insensitive" is the closest synonym. "Careless" implies negligence, not emotional coldness. "Passive" = inactive.' },
    { id: 183, type: 'mcq', section: 'Synonyms', question: 'Find the synonym of "PROSCRIBE":', parts: { A: 'Prescribe', B: 'Forbid', C: 'Promote', D: 'Encourage' }, answer: 'B', explanation: 'Exact JIPMAT 2025 Q82 — Proscribe = to officially forbid something by law or authority. "Prescribe" is the classic spelling/meaning trap — it means to recommend or authorize. "Forbid" is the correct synonym.' },
    { id: 184, type: 'mcq', section: 'Synonyms', question: 'Find the synonym of "COMMUNICABLE":', parts: { A: 'Communication', B: 'Understandable', C: 'Contagious', D: 'Commendable' }, answer: 'C', explanation: 'Exact JIPMAT 2023 Q95 — Communicable (of a disease) = able to be transmitted from one person to another = Contagious. "Commendable" (worthy of praise) is a sound-alike trap. "Understandable" relates to comprehension, not transmission.' },

    // ── SECTION W: Antonyms ──
    { id: 185, type: 'mcq', section: 'Antonyms', question: 'Find the antonym of "JOCUND":', parts: { A: 'Jealous', B: 'Cheerful', C: 'Gloomy', D: 'Optimistic' }, answer: 'C', explanation: 'Exact JIPMAT 2022 Q99 — Jocund = cheerful and light-hearted. Its antonym is Gloomy (dark and unhappy). Note: "Cheerful" is a synonym, not an antonym. Watch out for synonym-placed-as-option traps.' },
    { id: 186, type: 'mcq', section: 'Antonyms', question: 'Find the antonym of "DISSIMULATE":', parts: { A: 'Concrete', B: 'Circulate', C: 'Conceal', D: 'Reveal' }, answer: 'D', explanation: 'Exact JIPMAT 2022 Q96 — Dissimulate = to conceal or disguise one\'s true feelings. Its antonym is Reveal (to make known). "Conceal" is actually a synonym. "Circulate" and "Concrete" are distractors.' },
    { id: 187, type: 'mcq', section: 'Antonyms', question: 'Find the antonym of "CONSIDERATE":', parts: { A: 'Comprehensive', B: 'Indifferent', C: 'Malignant', D: 'Atrocious' }, answer: 'B', explanation: 'Exact JIPMAT 2023 Q74 — Considerate = thoughtful of others\' feelings and needs. Antonym = Indifferent (having no concern or consideration for others). Malignant and Atrocious have negative meanings but are not precise antonyms.' },
    { id: 188, type: 'mcq', section: 'Antonyms', question: 'Find the antonym of "COLOSSAL":', parts: { A: 'Epic', B: 'Vast', C: 'Tiny', D: 'Immense' }, answer: 'C', explanation: 'Exact JIPMAT 2025 Q72 — Colossal = extremely large and massive. Its antonym is Tiny (very small). Epic, Vast, and Immense all suggest great size and are thus synonyms, not antonyms.' },
    { id: 189, type: 'mcq', section: 'Antonyms', question: 'Find the antonym of "ENTREATY":', parts: { A: 'Immense', B: 'Command', C: 'Request', D: 'Hatred' }, answer: 'B', explanation: 'Exact JIPMAT 2025 Q80 — Entreaty = an earnest, humble request. Its antonym is Command (an authoritative order demanding compliance). "Request" is a synonym. "Hatred" is unrelated to the meaning of entreaty.' },
    { id: 190, type: 'mcq', section: 'Antonyms', question: 'Find the antonym of "EXPLICIT":', parts: { A: 'Clear', B: 'Direct', C: 'Implicit', D: 'Obvious' }, answer: 'C', explanation: 'Explicit = clearly and directly stated, leaving nothing implied. Antonym = Implicit = implied or suggested but not directly expressed. Clear, Direct, and Obvious are all synonyms of explicit.' },

    // ── SECTION X: Vocabulary in Context ──
    { id: 191, type: 'mcq', section: 'Vocabulary in Context', question: '"The attorney wanted to expedite the process, because her client was becoming impatient." The underlined word means:', parts: { A: 'Evaluate', B: 'Reverse', C: 'Accelerate', D: 'Justify' }, answer: 'C', explanation: 'Exact JIPMAT 2023 Q79 — Expedite = to make something happen sooner or be accomplished more quickly. "Accelerate" is the closest synonym. "Reverse" (go backwards) and "Evaluate" (assess) are unrelated meanings.' },
    { id: 192, type: 'mcq', section: 'Vocabulary in Context', question: '"Mr. Powers was so gullible that he believed even the most outlandish excuses." The underlined word means:', parts: { A: 'Intelligent', B: 'Dishonest', C: 'Critical', D: 'Naive' }, answer: 'D', explanation: 'Exact JIPMAT 2023 Q88 — Gullible = easily persuaded to believe something; credulous. "Naive" is the closest synonym. "Intelligent" is the antonym. "Dishonest" and "Critical" are unrelated to being easily deceived.' },
    { id: 193, type: 'mcq', section: 'Vocabulary in Context', question: '"Students are allowed only one resit." The underlined word means:', parts: { A: 'To take rest', B: 'To do creative work', C: 'To take an exam again', D: 'To do research' }, answer: 'C', explanation: 'Exact JIPMAT 2025 Q73 — Resit = to take an examination again, typically after failing or to improve a grade. The "re-" prefix indicates repetition. Option A is a sound-alike trap ("rest" vs "resit").' },
    { id: 194, type: 'mcq', section: 'Vocabulary in Context', question: '"The scientist\'s discovery was serendipitous." The underlined word means:', parts: { A: 'Planned meticulously', B: 'Happening by fortunate accident', C: 'Based on years of research', D: 'Controversial and disputed' }, answer: 'B', explanation: 'Serendipitous = occurring by a fortunate and unexpected chance. The word "serendipity" was coined by Horace Walpole from a Persian fairy tale. A and C suggest deliberate effort — the opposite of serendipity.' },
    { id: 195, type: 'mcq', section: 'Vocabulary in Context', question: '"The professor\'s explanation was so lucid that even the weakest students understood it." The underlined word means:', parts: { A: 'Complex and detailed', B: 'Brief and incomplete', C: 'Clear and easy to understand', D: 'Harsh and critical' }, answer: 'C', explanation: 'Lucid = expressed clearly and easy to understand; mentally clear. From Latin "lucidus" (bright, clear). It is often used to describe writing or speech that is brilliantly transparent in meaning.' },
    { id: 196, type: 'mcq', section: 'Vocabulary in Context', question: '"The bureaucratic process was so labyrinthine that few could navigate it." The underlined word means:', parts: { A: 'Transparent and simple', B: 'Extremely slow', C: 'Corrupt and unfair', D: 'Complicated and difficult to follow' }, answer: 'D', explanation: 'Labyrinthine = like a labyrinth (maze); intricate, complicated, and full of confusing twists. From the Greek myth of the Labyrinth. It describes complexity of structure, not slowness (B) or corruption (C).' },

    // ── SECTION Y: Sentence Improvement ──
    { id: 197, type: 'mcq', section: 'Sentence Improvement', question: '"Some forms of feminism have been criticised for take into account only middle-class perspectives." Choose the correct improvement for the underlined part:', parts: { A: 'to take in', B: 'for taking into', C: 'to take into', D: 'by take into' }, answer: 'B', explanation: 'Exact JIPMAT 2025 Q69 — "Criticised for" is followed by a gerund (verb+ing), not an infinitive. → "for taking into account". The preposition "for" governs the gerund "taking"; the phrasal verb is "take into account".' },
    { id: 198, type: 'mcq', section: 'Sentence Improvement', question: '"Happy is the man who acquired the habit of reading when he is young." Choose the correct improvement:', parts: { A: 'who acquires', B: 'who has been acquired', C: 'who acquire', D: 'which was acquiring' }, answer: 'A', explanation: 'Exact JIPMAT 2025 Q71 — The sentence uses present tense ("is young"), so the relative clause must also be present tense: "who acquires". "Acquired" (past) conflicts with "is young" (present). "Acquire" lacks the third-person "s".' },
    { id: 199, type: 'mcq', section: 'Sentence Improvement', question: '"She decided to not perform on the stage due to her ill health." Choose the correct version:', parts: { A: 'decided to not performing', B: 'decided not performing', C: 'decided not to perform', D: 'decided to not performed' }, answer: 'C', explanation: 'Exact JIPMAT 2023 Q81 — Negative infinitive: "not to + base verb". The "not" must come before "to", not after it. "Decided not to perform" is the standard form. Splitting the infinitive ("to not perform") is also incorrect in formal contexts.' },
    { id: 200, type: 'mcq', section: 'Sentence Improvement', question: '"Due to he was late, the meeting had to be postponed." Choose the correct improvement:', parts: { A: 'Because of his lateness being', B: 'Due to his lateness', C: 'Owing to him being late', D: 'Since he being late' }, answer: 'B', explanation: '"Due to" is a preposition — it must be followed by a noun/noun phrase, never a clause with a subject and verb. "Due to his lateness" uses a noun ("lateness"). Option D has no finite verb; Option A is awkward.' },
    { id: 201, type: 'mcq', section: 'Sentence Improvement', question: '"He requested her to reconsider the decision but she put her foot down." The underlined idiom means:', parts: { A: 'Agreed to reconsider', B: 'Ignored his request', C: 'Listened carefully', D: 'Refused to yield / took a firm stand' }, answer: 'D', explanation: '"Put one\'s foot down" = to firmly refuse to yield; to take a resolute stand. Tested in JIPMAT 2023/2025. It implies authority and refusal, not ignorance (B) or mere listening (C).' },

    // ── SECTION Z: Parallelism ──
    { id: 202, type: 'mcq', section: 'Parallelism', question: 'Which of the following sentences maintains correct parallel structure?', parts: { A: 'She likes reading, to write, and painting.', B: 'She likes reading, writing, and painting.', C: 'She likes to read, writing, and to paint.', D: 'She likes read, writing, and paint.' }, answer: 'B', explanation: 'Parallel structure requires all items in a list to be in the same grammatical form. B uses all gerunds (reading, writing, painting) — consistent and correct. A and C mix gerunds and infinitives. D uses uninflected verb forms incorrectly.' },
    { id: 203, type: 'mcq', section: 'Parallelism', question: 'Which sentence has faulty parallelism?', parts: { A: 'He is honest, hardworking, and dedicated.', B: 'The manager asked her to prepare the report, submit it on time, and present it clearly.', C: 'She enjoys singing, to dance, and acting.', D: 'The policy was clear, concise, and well-structured.' }, answer: 'C', explanation: '"Singing" (gerund) + "to dance" (infinitive) + "acting" (gerund) — inconsistent grammatical forms. All three should be gerunds: "singing, dancing, and acting". Options A, B, and D maintain consistent forms.' },
    { id: 204, type: 'mcq', section: 'Parallelism', question: 'Identify the sentence with correct parallel structure:', parts: { A: 'Not only did he write the report but also presented it.', B: 'Not only did he write the report but also he presented it.', C: 'Not only did he write the report but also did he present it.', D: 'Not only he wrote the report but also presented it.' }, answer: 'A', explanation: '"Not only did he write...but also presented it" — the auxiliary "did" governs both verbs (write and presented), making them balanced. B adds an unnecessary "he", creating imbalance. D uses wrong word order for the inversion.' },
    { id: 205, type: 'mcq', section: 'Parallelism', question: 'Which sentence has faulty parallelism?', parts: { A: 'The CEO was known for his vision, integrity, and leadership.', B: 'The new policy aims to reduce costs, improve efficiency, and increasing productivity.', C: 'She speaks Hindi, English, and French fluently.', D: 'The audit revealed errors in billing, reporting, and documentation.' }, answer: 'B', explanation: '"To reduce...improve...increasing" — the third element breaks the infinitive pattern. All three should be bare infinitives: "to reduce, improve, and increase productivity". A, C, D are all parallel.' },

    // ── SECTION AA: Gerund vs Infinitive ──
    { id: 206, type: 'mcq', section: 'Gerund vs Infinitive', question: '"Time and tide ___ for none."', parts: { A: 'waits', B: 'wait', C: 'waiting', D: 'had waited' }, answer: 'A', explanation: 'Exact JIPMAT 2023 Q77 — In the JIPMAT answer key, "waits" (singular) was the accepted answer, treating "Time and tide" as a fixed singular concept. The proverb conventionally uses "wait" (plural), but the exam recognised singular agreement.' },
    { id: 207, type: 'mcq', section: 'Gerund vs Infinitive', question: '"He is addicted to ___ video games for hours every night."', parts: { A: 'play', B: 'played', C: 'playing', D: 'have played' }, answer: 'C', explanation: '"Addicted to" — here "to" is a preposition (like "devoted to", "accustomed to"), not part of an infinitive. A preposition must be followed by a noun or gerund, not a bare verb. → "addicted to playing".' },
    { id: 208, type: 'mcq', section: 'Gerund vs Infinitive', question: '"She agreed ___ the new terms of the partnership contract."', parts: { A: 'accepting', B: 'to accept', C: 'for accepting', D: 'on accepting' }, answer: 'B', explanation: '"Agree to + infinitive" is the correct pattern for consenting to a proposal or plan. "Agree on" means to reach a mutual decision together. "Agree for/accepting" are not standard constructions.' },
    { id: 209, type: 'mcq', section: 'Gerund vs Infinitive', question: '"The director suggested ___ an expert consultant for the restructuring."', parts: { A: 'to hire', B: 'hire', C: 'hiring', D: 'to hiring' }, answer: 'C', explanation: '"Suggest" is always followed by a gerund (verb+ing), not an infinitive. Other verbs that take gerunds: avoid, consider, deny, enjoy, finish, practise. → "suggested hiring". Compare: "recommend hiring" (same pattern).' },
    { id: 210, type: 'mcq', section: 'Gerund vs Infinitive', question: '"I look forward to ___ from you at the earliest."', parts: { A: 'hear', B: 'heard', C: 'having heard', D: 'hearing' }, answer: 'D', explanation: '"Look forward to" — here "to" is a preposition, not part of an infinitive. Therefore it must be followed by a gerund: "hearing". Common trap: students write "look forward to hear" treating "to" as part of the infinitive.' },
    { id: 211, type: 'mcq', section: 'Gerund vs Infinitive', question: '"She avoided ___ direct eye contact during the difficult conversation."', parts: { A: 'to make', B: 'made', C: 'make', D: 'making' }, answer: 'D', explanation: '"Avoid" is a verb that always takes a gerund, never an infinitive. Memory aid: RAPS verbs (Resist, Avoid, Practise, Suggest) all take gerunds. → "avoided making".' },
    { id: 212, type: 'mcq', section: 'Gerund vs Infinitive', question: '"He decided ___ the company immediately after the board meeting."', parts: { A: 'leaving', B: 'to leave', C: 'for leaving', D: 'on leave' }, answer: 'B', explanation: '"Decide to + infinitive" is the correct construction. Other verbs taking infinitives: agree, choose, expect, hope, plan, promise, refuse, want. → "decided to leave". "Decide on + gerund/noun" has a different meaning (make a choice).' },
    { id: 213, type: 'mcq', section: 'Gerund vs Infinitive', question: '"They insisted ___ the matter be referred to an independent committee."', parts: { A: 'for', B: 'that', C: 'on', D: 'about' }, answer: 'B', explanation: '"Insist that + subject + subjunctive verb" is correct when a clause follows (that the matter be referred). "Insist on + gerund" is used when no subject follows (insisted on reviewing). Here a full clause follows → "insisted that".' },

    // ── SECTION BB: Punctuation ──
    { id: 214, type: 'mcq', section: 'Punctuation', question: '"What a good man he is ___" Choose the most appropriate punctuation mark:', parts: { A: '. (full stop)', B: '? (question mark)', C: '! (exclamation mark)', D: ': (colon)' }, answer: 'C', explanation: 'Exact JIPMAT 2025 Q70 — This is an exclamatory sentence expressing admiration ("What a..."). It requires an exclamation mark (!). A question mark is for interrogative sentences; a full stop is for declarative sentences.' },
    { id: 215, type: 'mcq', section: 'Punctuation', question: 'Which of the following is correctly punctuated?', parts: { A: '"The manager said, that the report was incomplete."', B: 'The manager said that the report was incomplete.', C: 'The manager said; that the report was incomplete.', D: 'The manager said: that, the report was incomplete.' }, answer: 'B', explanation: 'In indirect/reported speech, no comma, colon, or semicolon is needed before "that". The clause flows naturally from the reporting verb. A comma before "that" (direct speech style) is incorrect in indirect speech.' },
    { id: 216, type: 'mcq', section: 'Punctuation', question: 'Which sentence uses the apostrophe correctly?', parts: { A: "The companies' merger was approved by all it's shareholders.", B: "The company's merger was approved by all its shareholders.", C: "The companys' merger was approved by all its' shareholders.", D: "The companies merger was approved by all its shareholders'." }, answer: 'B', explanation: 'B is correct throughout: "company\'s" = possessive singular (one company); "its" = possessive pronoun (no apostrophe — "it\'s" always means "it is"). C uses wrong apostrophe placement; A confuses "its/it\'s".' },

    // ── SECTION CC: Redundancy and Pleonasm ──
    { id: 217, type: 'mcq', section: 'Redundancy & Pleonasm', question: 'Identify the sentence with a redundant expression:', parts: { A: 'He returned to his hometown after many years.', B: 'She gave a brief summary of the key findings.', C: 'He returned back to his hometown after many years.', D: 'The committee reviewed the final draft.' }, answer: 'C', explanation: '"Returned back" is redundant — "return" already means to go back. Adding "back" repeats the meaning. → "He returned to his hometown". Compare: "revert back" (same error) — "revert" already implies going back.' },
    { id: 218, type: 'mcq', section: 'Redundancy & Pleonasm', question: 'Identify the redundant expression:', parts: { A: 'The two countries reached a consensus on the trade deal.', B: 'The two countries reached a mutual consensus on the trade deal.', C: 'Both parties agreed on the terms.', D: 'An agreement was signed after prolonged negotiations.' }, answer: 'B', explanation: '"Consensus" already means general agreement among a group — adding "mutual" is redundant because agreement is by nature mutual. Similarly, "mutual agreement" and "general consensus" are both pleonasms.' },
    { id: 219, type: 'mcq', section: 'Redundancy & Pleonasm', question: 'Identify the sentence with a pleonasm (unnecessary repetition):', parts: { A: 'He made an indirect allusion to the scandal.', B: 'The annual event is held every year.', C: 'Both A and B', D: 'Neither A nor B' }, answer: 'C', explanation: 'Both are pleonasms: "Allusion" already means an indirect reference (so "indirect allusion" is redundant); "Annual" already means yearly (so "every year" is redundant). Both sentences are guilty — hence C.' },
    { id: 220, type: 'mcq', section: 'Redundancy & Pleonasm', question: 'Which of the following does NOT contain a redundant expression?', parts: { A: 'They collaborated together on the project.', B: 'She made a forward advance toward the goal.', C: 'The two options were completely identical to each other.', D: 'She made significant progress in her research.' }, answer: 'D', explanation: 'A — "collaborated together" (collaborate already means working together); B — "forward advance" (advance already implies forward movement); C — "completely identical to each other" (identical already implies complete sameness). D is clean.' },

    // ── SECTION DD: Confusables ──
    { id: 221, type: 'mcq', section: 'Confusables', question: '"Education is ___ instrument which imparts knowledge."', parts: { A: 'a', B: 'an', C: 'the', D: 'no article needed' }, answer: 'B', explanation: 'Exact JIPMAT 2025 Q77 — "Instrument" begins with a vowel sound /ɪ/, so "an" is required. "A" is used before consonant sounds. This is a straightforward article rule but easily missed when reading quickly.' },
    { id: 222, type: 'mcq', section: 'Confusables', question: '"The accused was given ___ opportunity to present his defence."', parts: { A: 'a', B: 'an', C: 'the', D: 'no article' }, answer: 'B', explanation: '"Opportunity" starts with a vowel sound /ɒ/ → "an opportunity". "A" would be incorrect because the following word begins with a vowel sound. "The" would imply a specific, previously mentioned opportunity.' },
    { id: 223, type: 'mcq', section: 'Confusables', question: 'The ___ reason for the company\'s turnaround was cost efficiency.', parts: { A: 'principle', B: 'principal', C: 'main-principle', D: 'principled' }, answer: 'B', explanation: '"Principal" (adjective) = main or chief. "Principle" = a fundamental rule or belief (noun only). Mnemonic: "the principal is your PAL" — principal as an adjective means main. "Principled" means having strong principles.' },
    { id: 224, type: 'mcq', section: 'Confusables', question: 'The new strategy will ___ the company\'s market position significantly.', parts: { A: 'effect', B: 'affect', C: 'affection', D: 'effective' }, answer: 'B', explanation: '"Affect" (verb) = to influence or have an impact on. "Effect" (noun) = a result or outcome; "Effect" as a verb means to bring about (rare). The blank needs a verb → "affect". Mnemonic: RAVEN — Remember, Affect = Verb, Effect = Noun.' },
    { id: 225, type: 'mcq', section: 'Confusables', question: 'The office ___ purchase included notebooks, pens, and staplers.', parts: { A: 'stationary', B: 'stationery', C: 'stationer', D: "stationary's" }, answer: 'B', explanation: '"Stationery" (noun, with e) = writing materials and office supplies. "Stationary" (adjective, with a) = not moving or changing. Mnemonic: stationERy has an E for Envelope — office supplies.' },
    { id: 226, type: 'mcq', section: 'Confusables', question: 'She has a natural ___ for languages and picks them up very quickly.', parts: { A: 'flare', B: 'flair', C: 'fleur', D: 'flaw' }, answer: 'B', explanation: '"Flair" = a natural talent or aptitude. "Flare" = a sudden burst of flame or a signal; also a type of trouser. "Fleur" is French for flower. "Flaw" means a defect. → "flair for languages".' },
    { id: 227, type: 'mcq', section: 'Confusables', question: 'The patient was advised to take the medicine at ___ intervals.', parts: { A: 'regular', B: 'regulator', C: 'regularly', D: 'regularise' }, answer: 'A', explanation: 'The blank modifies the noun "intervals" — an adjective is needed. "Regular" (adjective) = occurring at fixed intervals. "Regularly" is an adverb and cannot modify a noun. "Regulator" and "regularise" are unrelated parts of speech here.' },
    { id: 228, type: 'mcq', section: 'Confusables', question: 'The ___ effects of the medicine wore off after a few hours.', parts: { A: 'temporary', B: 'temporal', C: 'temporarily', D: 'temporise' }, answer: 'A', explanation: '"Temporary" (adjective) = lasting for only a limited time. "Temporal" = relating to time or worldly (secular) matters — a different meaning. "Temporarily" is an adverb (cannot modify "effects" as adjective). "Temporise" = to delay making a decision.' },

    // ── SECTION EE: Para-Jumbles ──
    { id: 229, type: 'mcq', section: 'Para-Jumbles', question: 'Arrange the following parts to make a meaningful sentence:\nP. for five years, I was sure\nQ. when I decided to go abroad\nR. that my grandmother would be upset\nS. and at her age one could never tell', parts: { A: 'R, S, P, Q', B: 'P, S, R, Q', C: 'S, P, Q, R', D: 'Q, P, R, S' }, answer: 'D', explanation: 'Exact JIPMAT 2022 Q90 — Logical flow: "When I decided to go abroad (Q), for five years I was sure (P), that my grandmother would be upset (R), and at her age one could never tell (S)." Q sets the time frame; P expresses certainty; R gives the content; S adds uncertainty.' },
    { id: 230, type: 'mcq', section: 'Para-Jumbles', question: 'Arrange the following parts to make a meaningful sentence:\nP. responsible for anything\nQ. we would be held\nR. that went wrong\nS. we were told that', parts: { A: 'R, Q, P, S', B: 'S, Q, P, R', C: 'S, Q, R, P', D: 'P, Q, R, S' }, answer: 'B', explanation: 'Exact JIPMAT 2022 Q100 — "We were told that (S) we would be held (Q) responsible for anything (P) that went wrong (R)." S introduces the reporting clause; Q begins the reported clause; P+R complete the predicate. → S, Q, P, R.' },
    { id: 231, type: 'mcq', section: 'Para-Jumbles', question: 'Arrange to form a meaningful paragraph:\nA. Such an intervention in political reforms in India has got inspiration from western societies.\nB. These organisations have emphasised an approach towards political democracy rooted in civil society.\nC. The ever-widening group of middle-class Indians is using NGOs to plant the idea of rights.\nD. And while it is still early days, this trend carries great promise.\nE. This bottom-up civil consciousness can bring in a new kind of democracy in India.', parts: { A: 'C, D, A, B, E', B: 'A, E, B, D, C', C: 'E, B, A, D, C', D: 'B, D, E, A, C' }, answer: 'A', explanation: 'Exact JIPMAT 2025 Q92 — C (introduces NGOs/middle class) → D (acknowledges it is early stage) → A (traces western inspiration) → B (emphasises civil society approach) → E (conclusion: new kind of democracy). → C, D, A, B, E.' },
    { id: 232, type: 'mcq', section: 'Para-Jumbles', question: 'Arrange the following parts to make a meaningful sentence:\nP. around the town\nQ. when I was young,\nR. delivering food to customers\nS. shopkeepers would cycle', parts: { A: 'R, S, P, Q', B: 'Q, S, P, R', C: 'S, R, Q, P', D: 'P, Q, R, S' }, answer: 'B', explanation: 'Exact JIPMAT 2023 Q80 — "When I was young (Q), shopkeepers would cycle (S) around the town (P) delivering food to customers (R)." Q sets the time clause; S is the main clause subject+verb; P is place; R is the participle phrase of purpose.' },
    { id: 233, type: 'mcq', section: 'Para-Jumbles', question: 'Arrange the following parts to make a meaningful sentence:\nP. an extra person\nQ. this card entitles\nR. with you free\nS. you to take', parts: { A: 'Q, S, P, R', B: 'P, Q, R, S', C: 'R, P, Q, S', D: 'S, Q, R, P' }, answer: 'A', explanation: 'Exact JIPMAT 2023 Q82 — "This card entitles (Q) you to take (S) an extra person (P) with you free (R)." Q is the subject+verb; S continues with "you to take" (object+infinitive); P is the direct object; R completes the adverb phrase.' },

    // ── SECTION FF: Double Blank Completion ──
    { id: 234, type: 'mcq', section: 'Double Blank Completion', question: '"We are truly ___ to the many hands and hearts that made this book ___."', parts: { A: 'obliged … plausible', B: 'thankful … flexible', C: 'grateful … possible', D: 'honoured … feasible' }, answer: 'C', explanation: 'Exact JIPMAT 2022 Q85 — "Grateful" = feeling or showing thanks; "possible" = able to be done or achieved. This is the only pair where both words fit the meaning and collocate naturally with the sentence context.' },
    { id: 235, type: 'mcq', section: 'Double Blank Completion', question: '"The doctor ___ a special course of antibiotics on the patient to ___ the disease."', parts: { A: 'used … relieve', B: 'gave … fake out', C: 'prescribed … prove', D: 'administered … combat' }, answer: 'D', explanation: 'Exact JIPMAT 2022 Q70 — "Administered" = formally gave/applied medication; "combat" = fight or overcome. "Prescribed" is plausible for blank 1, but "prove" makes no sense for blank 2. D is the only pair that works semantically throughout.' },
    { id: 236, type: 'mcq', section: 'Double Blank Completion', question: '"The ___ of new projects in the energy sector is ___ not only on profitability but also on sustainability."', parts: { A: 'planning … vulnerable', B: 'occurrence … premised', C: 'starting … possible', D: 'initiation … dependent' }, answer: 'D', explanation: 'Exact JIPMAT 2025 Q86 — "Initiation" = the process of beginning something (formal noun for starting projects); "dependent" = contingent upon. "Dependent on" collocates correctly. "Premised on" (B) is also possible but "occurrence" is wrong for blank 1.' },
    { id: 237, type: 'mcq', section: 'Double Blank Completion', question: '"The new trade agreement will ___ the growth of domestic industries and ___ foreign investment."', parts: { A: 'hamper … discourage', B: 'accelerate … attract', C: 'stagnate … promote', D: 'restrict … enhance' }, answer: 'B', explanation: 'The sentence is positive in tone and about benefits of a trade agreement. "Accelerate growth" + "attract investment" is the only pair that is both logically consistent and positively oriented. A and D are negative; C is self-contradictory.' },
    { id: 238, type: 'mcq', section: 'Double Blank Completion', question: '"A leader who is ___ to criticism often fails to ___ the trust of the team."', parts: { A: 'open … lose', B: 'averse … retain', C: 'responsive … betray', D: 'immune … build' }, answer: 'B', explanation: 'Logical cause-effect: a leader "averse to criticism" (resisting feedback) "fails to retain the trust" of the team — because dismissing feedback damages trust. A is contradictory (open to criticism should NOT lose trust). D (immune/build) does not flow logically.' },

    // ── SECTION GG: Reported Speech (Advanced) ──
    { id: 239, type: 'mcq', section: 'Reported Speech', question: '"He said to me, \'What are you doing?\'" Choose the correct indirect speech:', parts: { A: 'He asked me what he was doing.', B: 'He asked me that what I was doing.', C: 'He asked me what I was doing.', D: 'He asked me why I was doing.' }, answer: 'C', explanation: 'Exact JIPMAT 2022 Q87 — Indirect WH-question rule: remove quotation marks → backshift tense (are→was) → statement word order (I was doing, not was I doing) → remove "?" → change pronouns (you→I). "That" is never inserted before WH-words.' },
    { id: 240, type: 'mcq', section: 'Reported Speech', question: '"She said to him, \'Please wait here till I return.\'" Choose the correct indirect speech:', parts: { A: 'She requested her to wait there till she returned.', B: 'She requested him to wait there till she returned.', C: 'She requested him to wait there till she returns.', D: 'She requests him to wait there till she had returned.' }, answer: 'B', explanation: 'Exact JIPMAT 2023 Q67 — "Please" signals a request → "requested him to". Pronoun: "him" (not "her"). Place: "here"→"there". Tense backshift: "I return"→"she returned". "Returns" (C) fails to backshift; "had returned" (D) is over-backshifted.' },
    { id: 241, type: 'mcq', section: 'Reported Speech', question: '"He said, \'How wise I am!\'" Choose the correct indirect speech:', parts: { A: 'He exclaimed that I was very wise.', B: 'He regretted that he was very wise.', C: 'He exclaimed that he was very wise.', D: 'He exclaimed that I am very wise.' }, answer: 'C', explanation: 'Exact JIPMAT 2022 Q95 — Exclamatory sentence: "exclaimed that" + positive statement. Pronoun change: "I"→"he" (third person). Tense backshift: "am"→"was". A uses wrong pronoun "I"; D fails to backshift tense; B uses wrong reporting verb.' },
    { id: 242, type: 'mcq', section: 'Reported Speech', question: '"She said to him, \'Let us wait for the award.\'" Choose the correct indirect speech:', parts: { A: 'She proposed him to wait for the award.', B: 'She agreed to wait for the award with him.', C: 'She proposed me that I should wait for the award.', D: 'She proposed that they should wait for the award.' }, answer: 'D', explanation: 'Exact JIPMAT 2023 Q75 — "Let us" = a proposal/suggestion → "proposed that they should". "Let us" is inclusive (speaker + listener) → "they". "Proposed him to" (A) is not standard English; "proposed me" (C) has wrong pronoun.' },
    { id: 243, type: 'mcq', section: 'Reported Speech', question: '"Pritha said to me, \'We have to win this trophy.\'" Choose the correct indirect speech:', parts: { A: 'Pritha told me that they have to win that trophy.', B: 'Pritha told me that we had to win that trophy.', C: 'Pritha told me that we have to win that trophy.', D: 'Pritha told me that they had to win that trophy.' }, answer: 'D', explanation: 'Exact JIPMAT 2025 Q67 — "We" (Pritha + listener = "they" when reported by the listener); tense backshift: "have to"→"had to"; demonstrative: "this"→"that". B keeps "we" (wrong — listener should not be included in "we" when reporting); A fails to backshift.' },

    // ── SECTION HH: Determiners ──
    { id: 244, type: 'mcq', section: 'Determiners', question: '"___ student in the class passed the examination with distinction."', parts: { A: 'All', B: 'Every', C: 'Each of the', D: 'Many' }, answer: 'B', explanation: '"Every student" (singular noun) takes a singular verb "passed" — grammatically correct. "All students" would need "All the students passed". "Each of the students" is possible but "passed" without plural agreement is odd. "Every" is the cleanest fit.' },
    { id: 245, type: 'mcq', section: 'Determiners', question: '"There is ___ water left in the reservoir — we must conserve it."', parts: { A: 'few', B: 'a few', C: 'little', D: 'a little' }, answer: 'C', explanation: '"Water" is uncountable. Use "little/a little" (not "few/a few" which are for countable nouns). "Little" carries a negative implication (not much — cause for concern), fitting "we must conserve it". "A little" would suggest enough remains (positive).' },
    { id: 246, type: 'mcq', section: 'Determiners', question: '"___ of his suggestions were accepted by the board at the annual review."', parts: { A: 'Few', B: 'Little', C: 'Much', D: 'A little' }, answer: 'A', explanation: '"Suggestions" is countable and plural — use "few/a few/many", not "little/much" (which are for uncountable). "Few" (without "a") = not many, negative implication — implies disappointment, which fits the context.' },
    { id: 247, type: 'mcq', section: 'Determiners', question: '"She has ___ experience in corporate law to handle this case independently."', parts: { A: 'too much', B: 'enough', C: 'a little of', D: 'many' }, answer: 'B', explanation: '"Enough experience" = sufficient experience. "Experience" is uncountable → not "many". "Too much experience" would mean she has more than needed (doesn\'t imply inability). "A little of" is not standard before an abstract noun without an article.' },
    { id: 248, type: 'mcq', section: 'Determiners', question: '"___ information was available at the time the decision was made."', parts: { A: 'Few', B: 'Many', C: 'Little', D: 'A few' }, answer: 'C', explanation: '"Information" is an uncountable noun → use "little" (not much) or "much". "Few" and "A few" are for countable nouns. "Little information" = not much information was available. This is a standard determiner-countability agreement test.' },

    // ── SECTION II: Negation Errors ──
    { id: 249, type: 'mcq', section: 'Negation Errors', question: 'Which of the following sentences uses negation correctly?', parts: { A: "I didn't see nobody at the office.", B: "She doesn't have no experience in finance.", C: "He has never missed a board meeting since he became chairman.", D: "They don't have nothing to declare at customs." }, answer: 'C', explanation: 'C is correct — "never missed" is a standard single-negation construction. A, B, and D all use double negatives: "didn\'t...nobody", "doesn\'t...no", "don\'t...nothing" — each pair creates a double negative, which is incorrect in standard English.' },
    { id: 250, type: 'mcq', section: 'Negation Errors', question: 'Identify the sentence with a negation error:', parts: { A: "He could not help laughing at the situation.", B: "She hardly goes to the office on Fridays.", C: "They couldn't barely hear him over the noise.", D: "I have never been to that city before." }, answer: 'C', explanation: '"Couldn\'t barely" is a double negative — "couldn\'t" (negative) + "barely" (a near-negative/minimizer) together violate the standard English rule against double negation. Correct form: "could barely" or "couldn\'t clearly hear him". A, B, D are all correct.' },
];
